import React, { useState } from 'react';
import { Inbox, Send, Trash2, Edit, Search, Star } from 'lucide-react';
import './css/Messaging.css';

const Messaging = ({ userId }) => {
    const [activeCategory, setActiveCategory] = useState('inbox');
    const [messages, setMessages] = useState([
        { id: 1, from: 'John Doe', subject: 'Hello!', content: 'Hi there, how are you?', date: '2023-05-01', read: false, starred: false },
        { id: 2, from: 'Jane Smith', subject: 'Meeting tomorrow', content: 'Don\'t forget about our meeting tomorrow at 2 PM.', date: '2023-04-30', read: true, starred: true },
        { id: 3, from: 'Alice Johnson', subject: 'Project update', content: 'I\'ve finished the first draft of the project. Please review when you have a chance.', date: '2023-04-29', read: true, starred: false },
    ]);
    const [selectedMessage, setSelectedMessage] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');

    const filteredMessages = messages.filter(message => 
        message.from.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.content.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const renderMessageList = () => {
        return filteredMessages.map(message => (
            <div 
                key={message.id} 
                className={`message-item ${!message.read ? 'unread' : ''} ${message.starred ? 'starred' : ''} ${selectedMessage && selectedMessage.id === message.id ? 'selected' : ''}`}
                onClick={() => setSelectedMessage(message)}
            >
                <div className="message-item-content">
                    <div className="message-header">
                        <span className="message-from">{message.from}</span>
                        <span className="message-date">{message.date}</span>
                    </div>
                    <div className="message-subject">{message.subject}</div>
                    <div className="message-preview">{message.content}</div>
                </div>
                <button className="star-btn" onClick={(e) => {
                    e.stopPropagation();
                    setMessages(messages.map(m => m.id === message.id ? {...m, starred: !m.starred} : m));
                }}>
                    <Star size={16} className={message.starred ? 'starred' : ''} />
                </button>
            </div>
        ));
    };

    const renderMessageDetail = () => {
        if (!selectedMessage) return null;
        return (
            <div className="message-detail">
                <h3>{selectedMessage.subject}</h3>
                <div className="message-info">
                    <span>From: {selectedMessage.from}</span>
                    <span>Date: {selectedMessage.date}</span>
                </div>
                <div className="message-content">{selectedMessage.content}</div>
                <button className="reply-btn" onClick={() => {/* Implement reply functionality */}}>
                    Reply
                </button>
            </div>
        );
    };

    return (
        <div className="messaging-container">
            <div className="messaging-sidebar">
                <button className="new-message-btn">
                    <Edit size={18} />
                    New Message
                </button>
                <div className="message-categories">
                    <button
                        className={`category-btn ${activeCategory === 'inbox' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('inbox')}
                    >
                        <Inbox size={18} />
                        Inbox
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'sent' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('sent')}
                    >
                        <Send size={18} />
                        Sent
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'trash' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('trash')}
                    >
                        <Trash2 size={18} />
                        Trash
                    </button>
                </div>
            </div>
            <div className="messaging-content">
                <div className="messaging-header">
                    <h2>{activeCategory.charAt(0).toUpperCase() + activeCategory.slice(1)}</h2>
                    <div className="search-bar">
                        <input 
                            type="text" 
                            placeholder="Search messages..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        <Search size={18} />
                    </div>
                </div>
                <div className="message-list-container">
                    <div className="message-list">
                        {renderMessageList()}
                    </div>
                    <div className="message-detail-container">
                        {renderMessageDetail()}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Messaging;
